  "inlineSchema": "// Prisma Schema for NannyOra\n// Using SQLite for local dev, easily switchable to PostgreSQL\n\ngenerator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"sqlite\"\n  url      = env(\"DATABASE_URL\")\n}\n\n// ============================================================\n// User & Auth\n// ============================================================\n\nmodel User {\n  id           String   @id @default(cuid())\n  email        String   @unique\n  passwordHash String\n  name         String\n  phone        String?\n  role         String   @default(\"PARENT\") // PARENT, NANNY, ADMIN\n  image        String?\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  parentProfile ParentProfile?\n  nannyProfile  NannyProfile?\n  jobPosts      JobPost[]\n  enquiriesSent Enquiry[]      @relation(\"EnquiriesSent\")\n  reviewsGiven  Review[]       @relation(\"ReviewsGiven\")\n\n  @@map(\"users\")\n}\n\n// ============================================================\n// Parent Profile\n// ============================================================\n\nmodel ParentProfile {\n  id              String   @id @default(cuid())\n  userId          String   @unique\n  user            User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  suburb          String\n  childAgeRange   String // JSON array stored as string\n  careTypeNeeded  String // JSON array stored as string\n  preferredDays   String\n  startDate       String?\n  specialistNeeds String   @default(\"\")\n  notes           String   @default(\"\")\n  createdAt       DateTime @default(now())\n  updatedAt       DateTime @updatedAt\n\n  @@map(\"parent_profiles\")\n}\n\n// ============================================================\n// Nanny Profile\n// ============================================================\n\nmodel NannyProfile {\n  id                     String   @id @default(cuid())\n  userId                 String   @unique\n  user                   User     @relation(fields: [userId], references: [id], onDelete: Cascade)\n  suburb                 String\n  areasCovered           String // JSON array stored as string\n  yearsExperience        Int\n  careTypes              String // JSON array stored as string\n  qualifications         String   @default(\"\") // JSON array stored as string\n  eceExperience          Boolean  @default(false)\n  neurodiverseExperience Boolean  @default(false)\n  firstAidCurrent        Boolean  @default(false)\n  driverLicence          Boolean  @default(false)\n  hourlyRate             Int\n  bio                    String\n  availabilitySummary    String   @default(\"\")\n  availability           String   @default(\"[]\") // JSON array stored as string\n  specialistTags         String   @default(\"[]\") // JSON array stored as string\n  verificationLevel      String   @default(\"LISTED\") // LISTED, VERIFIED, PREMIUM_VETTED, SPECIALIST\n  adminStatus            String   @default(\"SUBMITTED\") // DRAFT, SUBMITTED, UNDER_REVIEW, APPROVED, VERIFIED, SPECIALIST, SUSPENDED, ARCHIVED\n  profileImageUrl        String?\n  createdAt              DateTime @default(now())\n  updatedAt              DateTime @updatedAt\n\n  documents         NannyDocument[]\n  enquiriesReceived Enquiry[]       @relation(\"EnquiriesReceived\")\n  reviewsReceived   Review[]        @relation(\"ReviewsReceived\")\n\n  @@map(\"nanny_profiles\")\n}\n\n// ============================================================\n// Nanny Documents\n// ============================================================\n\nmodel NannyDocument {\n  id             String       @id @default(cuid())\n  nannyProfileId String\n  nannyProfile   NannyProfile @relation(fields: [nannyProfileId], references: [id], onDelete: Cascade)\n  documentType   String // ID, REFERENCES, FIRST_AID_CERT, POLICE_VET, TEACHER_REGISTRATION\n  fileName       String\n  fileUrl        String?\n  reviewStatus   String       @default(\"PENDING\") // PENDING, APPROVED, REJECTED\n  reviewedAt     DateTime?\n  reviewedBy     String?\n  createdAt      DateTime     @default(now())\n\n  @@map(\"nanny_documents\")\n}\n\n// ============================================================\n// Job Posts\n// ============================================================\n\nmodel JobPost {\n  id                String   @id @default(cuid())\n  parentId          String\n  parent            User     @relation(fields: [parentId], references: [id], onDelete: Cascade)\n  title             String\n  suburb            String\n  careType          String\n  daysRequired      String\n  childCount        Int\n  childAges         String\n  startDate         String\n  hourlyBudget      Int\n  specialistSupport String   @default(\"\")\n  description       String\n  status            String   @default(\"PENDING\") // PENDING, APPROVED, CLOSED, REJECTED\n  contactEmail      String\n  contactPhone      String?\n  createdAt         DateTime @default(now())\n  updatedAt         DateTime @updatedAt\n\n  @@map(\"job_posts\")\n}\n\n// ============================================================\n// Enquiries\n// ============================================================\n\nmodel Enquiry {\n  id        String       @id @default(cuid())\n  parentId  String\n  parent    User         @relation(\"EnquiriesSent\", fields: [parentId], references: [id], onDelete: Cascade)\n  nannyId   String\n  nanny     NannyProfile @relation(\"EnquiriesReceived\", fields: [nannyId], references: [id], onDelete: Cascade)\n  message   String\n  status    String       @default(\"NEW\") // NEW, CONTACTED, MATCHED, CLOSED\n  createdAt DateTime     @default(now())\n  updatedAt DateTime     @updatedAt\n\n  @@map(\"enquiries\")\n}\n\n// ============================================================\n// Reviews (placeholder for Phase 2)\n// ============================================================\n\nmodel Review {\n  id        String       @id @default(cuid())\n  parentId  String\n  parent    User         @relation(\"ReviewsGiven\", fields: [parentId], references: [id], onDelete: Cascade)\n  nannyId   String\n  nanny     NannyProfile @relation(\"ReviewsReceived\", fields: [nannyId], references: [id], onDelete: Cascade)\n  rating    Int          @default(5)\n  comment   String\n  createdAt DateTime     @default(now())\n\n  @@map(\"reviews\")\n}\n\n// ============================================================\n// Skill Tags (for nanny specialisations)\n// ============================================================\n\nmodel SkillTag {\n  id       String @id @default(cuid())\n  name     String @unique\n  category String @default(\"general\") // general, specialist, qualification\n\n  @@map(\"skill_tags\")\n}\n",
